import{G as s,c as i,b as e,ae as t}from"./chunks/framework.Cpb2nuHT.js";const o=JSON.parse('{"title":"MySQL 触发器","description":"","frontmatter":{"title":"MySQL 触发器","date":"2024-08-07T14:16:14.000Z","tags":["MySQL"],"author":"花木凋零成兰"},"headers":[],"relativePath":"Database/MySQL/MySQL触发器.md","filePath":"Database/MySQL/MySQL触发器.md","lastUpdated":1723362724000}'),l={name:"Database/MySQL/MySQL触发器.md"};function n(r,a,h,p,E,k){return e(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1723040174000"},[...a[0]||(a[0]=[t(`<h1 id="mysql-触发器-trigger" tabindex="-1">MySQL 触发器(Trigger) <a class="header-anchor" href="#mysql-触发器-trigger" aria-label="Permalink to &quot;MySQL 触发器(Trigger)&quot;">​</a></h1><blockquote><p>MySQL 从 5.02 版本开始支持触发器, 触发器和存储过程一样, 是嵌入到 MySQL 服务器的一段程序;</p></blockquote><p>触发器是由 <strong>事件</strong> 来触发的某个操作, 这些事件包括 <code>INSERT</code>, <code>UPDATE</code>, &#39;DELETE&#39; 事件, 指在事件发生之前或之后触发并执行特定 SQL 语句的集合; 触发器可以协助开发人员与数据库交互过程中确保数据的完整性,日志记录和数据校验等;</p><p><strong>当对数据表中的数据执行插入、更新和删除操作时, 若需要自动执行一些数据库逻辑时, 可以使用触发器来实现;</strong></p><h2 id="类型" tabindex="-1">类型 <a class="header-anchor" href="#类型" aria-label="Permalink to &quot;类型&quot;">​</a></h2><p>现在触发器只支持行级触发, 不支持语句级触发; 使用别名 OLD 和 NEW 来引用触发器中发生变化的记录内容;</p><ul><li>INSERT 型触发器：NEW 表示将要或已经新增的数据;</li><li>UPDATE 型触发器：OLD 表示修改之前的数据, NEW 表示将要或已修改后的数据;</li><li>DELETE 型触发器：OLD 表示将要或者已经删除的数据;</li></ul><h2 id="语法" tabindex="-1">语法 <a class="header-anchor" href="#语法" aria-label="Permalink to &quot;语法&quot;">​</a></h2><p>语法结构如下所示：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TRIGGER</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> 触发器名称</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BEFORE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AFTER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} {</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DELETE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 表名 </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FOR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EACH </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ROW</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">触发器执行的语句块;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>说明：</p><ul><li>表名：表示触发器监控的对象;</li><li><code>BEFORE | AFTER</code>：表示触发时间, 在事件前或事件后触发;</li><li><code>INSERT | UPDATE | DELETE</code>：表示触发事件;</li><li>触发器执行的语句块：触发器被触发之后执行的 SQL 语句, 可以是单条 SQL 语句, 也可以是 BEGIN...END 结构组成的复合语句块;</li></ul><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://cloud.tencent.com/developer/article/1979884" target="_blank" rel="noreferrer">MySQL高级篇-慎用的触发器</a></li><li><a href="https://www.sqlboy.tech/pages/fa6960/" target="_blank" rel="noreferrer">MySQL 触发器</a></li></ul>`,14)])])}const c=s(l,[["render",n]]);export{o as __pageData,c as default};
